mapper.update:
UPDATE reply
SET content     = #{content},
    modify_date = SYSDATE
WHERE reply_no  = #{replyNo}
AND   member_no = #{memberNo}
AND   status    = 'Y'

UPDATE reply
SET status = 'N'
WHERE reply_no  = #{replyNo}
AND   member_no = #{memberNo}

mapper.select:
SELECT *
FROM (
	SELECT r.*, ROW_NUMBER() OVER (ORDER BY r.create_date DESC) AS rnum
	FROM reply r
	WHERE r.member_no = #{memberNo}
	  AND r.post_board = #{postBoard} AND r.status = 'Y'
)
WHERE rnum BETWEEN #{startRow} + 1 AND #{startRow} + #{listLimit}
